"""Serve the WebGPU SAM 3D page over Gradio's public share tunnel.

Why this exists: on SageMaker Studio, reaching a raw Flask port from the browser
needs jupyter-server-proxy (often missing) and a secure (https) context for
WebGPU. Gradio's `share=True` tunnel already gives a public **https** URL that
works in this environment (you've used it). This launcher piggybacks on that
tunnel: it starts a tiny Gradio app (just to get the tunnel + FastAPI server),
then attaches two raw routes to that same server:

    GET  /app       -> serves web/index.html (full page, scripts intact —
                       gr.HTML would strip them)
    POST /generate  -> proxies to the SageMaker endpoint (boto3, from app.py)

Both are reachable through the share tunnel, so the browser loads the WebGPU
page over https (secure context => WebGPU works) with no Jupyter proxy and no
local AWS creds.

Run:
    export AWS_REGION=us-east-1
    export SAM3D_ENDPOINT=sam3d-objects-g6e
    pip install gradio boto3
    python webapp_gradio.py
Then open the printed  https://....gradio.live/app  URL.
"""

import os

import gradio as gr
from starlette.concurrency import run_in_threadpool
from starlette.responses import HTMLResponse, JSONResponse
from starlette.routing import Route

from app import _default_invoke_factory

# index.html is embedded below (base64) so this file is fully self-contained —
# no separate web/ folder needs to be uploaded.
_INDEX_HTML_B64 = ""
_invoke = None
_JOBS = {}  # job_id -> {"status": "pending"|"done"|"error", ...}
import threading as _threading
import uuid as _uuid


def _get_invoke():
    global _invoke
    if _invoke is None:
        _invoke = _default_invoke_factory()
    return _invoke


async def _page(request):
    import base64 as _b64
    return HTMLResponse(_b64.b64decode(_INDEX_HTML_B64).decode("utf-8"))


def _run_job(job_id, payload):
    try:
        result = _get_invoke()(payload)
        if "ply_b64" in result:
            result["status"] = "done"
            _JOBS[job_id] = result
        else:
            _JOBS[job_id] = {"status": "error", "error": f"endpoint returned no model: {result}"}
    except Exception as exc:
        _JOBS[job_id] = {"status": "error", "error": str(exc)}


async def _generate(request):
    # Start the job in the background and return a job id immediately. Holding one
    # long request open (1-2 min reconstruction) trips the gradio.live tunnel's
    # ~60s timeout -> 504. The browser polls /poll instead (short requests).
    try:
        data = await request.json()
    except Exception as exc:
        return JSONResponse({"error": f"bad JSON: {exc}"}, status_code=400)
    if not data.get("image") or not data.get("mask"):
        return JSONResponse({"error": "image and mask are required"}, status_code=400)
    payload = {
        "image": data["image"],
        "mask": data["mask"],
        "seed": int(data.get("seed", 42)),
        "render_preview": False,
    }
    job_id = _uuid.uuid4().hex
    _JOBS[job_id] = {"status": "pending"}
    _threading.Thread(target=_run_job, args=(job_id, payload), daemon=True).start()
    return JSONResponse({"job_id": job_id})


async def _poll(request):
    job_id = request.query_params.get("id")
    job = _JOBS.get(job_id)
    if job is None:
        return JSONResponse({"status": "error", "error": "unknown job id"}, status_code=404)
    return JSONResponse(job)


def main():
    with gr.Blocks() as demo:
        gr.Markdown("### SAM 3D Objects (WebGPU)\nThe app is served at **`/app`** on this same URL — open the `…gradio.live/app` link printed in the terminal.")

    demo.launch(share=True, prevent_thread_lock=True)

    # Attach our routes to Gradio's FastAPI server AT THE FRONT so they take
    # priority over Gradio's catch-all SPA route. The share tunnel forwards them.
    demo.app.router.routes.insert(0, Route("/app", _page, methods=["GET"]))
    demo.app.router.routes.insert(0, Route("/generate", _generate, methods=["POST"]))
    demo.app.router.routes.insert(0, Route("/poll", _poll, methods=["GET"]))

    share = getattr(demo, "share_url", None)
    print("\n" + "=" * 70)
    print("OPEN THIS IN YOUR BROWSER (note the /app suffix):")
    print(f"   {share}/app" if share else "   <share url not ready — check above>")
    print("=" * 70 + "\n")

    try:
        demo.block_thread()  # keep the server alive (Ctrl-C to stop)
    except (AttributeError, KeyboardInterrupt):
        import time
        try:
            while True:
                time.sleep(3600)
        except KeyboardInterrupt:
            pass


if __name__ == "__main__":
    main()
